/**
 * Seed quiz questions for under-seeded courses:
 *   APCHEM, APSTAT, APCALCBC, APLIT, APBIZ, SATPREP, G8SS
 * Each unit gets 10 questions (mix of multiple_choice and short_answer).
 * Run: node server/seed-quiz-remaining-courses.mjs
 */
import mysql from "mysql2/promise";

const conn = await mysql.createConnection(process.env.DATABASE_URL);

// ─── Helper ───────────────────────────────────────────────────────────────────
const _sortCounters = {};
function mc(text, choices, correct, explanation, difficulty = "medium", unitId) {
  _sortCounters[unitId] = (_sortCounters[unitId] || 0) + 1;
  return { unitId, questionText: text, questionType: "multiple_choice", choices: JSON.stringify(choices.map((t,i)=>({label:String.fromCharCode(65+i),text:t}))), correctAnswer: correct, explanation, difficulty, skillTag: `UNIT-${unitId}`, sortOrder: _sortCounters[unitId] };
}
function sa(text, correct, explanation, difficulty = "medium", unitId) {
  _sortCounters[unitId] = (_sortCounters[unitId] || 0) + 1;
  return { unitId, questionText: text, questionType: "short_answer", choices: null, correctAnswer: correct, explanation, difficulty, skillTag: `UNIT-${unitId}`, sortOrder: _sortCounters[unitId] };
}

