const unitIds = [...new Set(allQuestions.map(q => q.unitId))];
for (const uid of unitIds) {
  await conn.execute("DELETE FROM quizQuestions WHERE unitId = ?", [uid]);
}

// Insert in batches of 50
const batchSize = 50;
let inserted = 0;
for (let i = 0; i < allQuestions.length; i += batchSize) {
  const batch = allQuestions.slice(i, i + batchSize);
  for (const q of batch) {
    await conn.execute(
      "INSERT INTO quizQuestions (unitId, questionText, questionType, choices, correctAnswer, explanation, skillTag, difficulty, sortOrder) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
      [q.unitId, q.questionText, q.questionType, q.choices, q.correctAnswer, q.explanation, q.skillTag, q.difficulty, q.sortOrder]
    );
    inserted++;
  }
  console.log(`  Inserted ${inserted}/${allQuestions.length}...`);
}

await conn.end();
console.log(`\n✅ Done! Inserted ${inserted} quiz questions across ${unitIds.length} units.`);
